export default class DevToolbar{constructor(t){this.app=t,this.el=null,this.init()}init(){this.el=document.createElement("div"),this.el.id="dev-toolbar",document.body.appendChild(this.el),this.update(),window.addEventListener("popstate",()=>this.update()),document.addEventListener("click",()=>{setTimeout(()=>this.update(),600)})}update(){const t=this.app.route.router.activeController,a=t?t.constructor.name:"None",e=t?.abortController?"ACTIVE":"INACTIVE";this.el.innerHTML=`\n            <div>\n                <span class="dev-tag">System: <span class="dev-active">Penryn v1.2</span></span>\n                <span class="dev-tag">Controller: <span class="dev-active">${a}</span></span>\n            </div>\n            <div>\n                <span class="dev-tag">AbortSignal: <span class="dev-active" style="color:${"ACTIVE"===e?"#00ff00":"#ff0000"}">${e}</span></span>\n                <span class="dev-tag">Path: <span class="dev-active">${window.location.pathname}</span></span>\n            </div>\n        `}}